Here are MSTest tests using modern assertions ideal for your scoring boundaries:

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(7, 10, 70.0)]
    [DataRow(1, 1, 100.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calculator.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_TotalIsZero_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(100.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        Assert.AreEqual(50.0, _calculator.NormalizeScore(25, 50));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        // IsInRange verifies the result stays within [0, 100]
        var result = _calculator.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calculator.NormalizeScore(0, 100));
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

**Key assertions used and why:**

| Assertion | Purpose |
|---|---|
| `Assert.AreEqual(expected, actual)` | Exact value checks (expected first!) |
| `Assert.ThrowsExactly<T>(() => ...)` | Validates guard clauses throw the exact exception type |
| `Assert.IsInRange(actual, low, high)` | Verifies a value stays within bounds |
| `[DataRow]` | Tests each grade boundary with minimal code |

The boundary strategy tests values **at** each threshold (90, 80, 70, 60) and just **below** (89.99, 79.99, etc.) to catch off-by-one errors in the `switch` expression.
